import{_ as t,o as e,c as l,a1 as i}from"./chunks/framework.qq2wtA-j.js";const p=JSON.parse('{"title":"TTML Trans Tool","description":"","frontmatter":{},"headers":[],"relativePath":"amll-cpp-qt/ttml-tool.md","filePath":"amll-cpp-qt/ttml-tool.md"}'),r={name:"amll-cpp-qt/ttml-tool.md"};function o(d,a,c,h,n,s){return e(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="ttml-trans-tool" tabindex="-1">TTML Trans Tool <a class="header-anchor" href="#ttml-trans-tool" aria-label="Permalink to &quot;TTML Trans Tool&quot;">​</a></h1><p>一个基于 C++ Qt 的高性能 TTML 歌词转换桌面工具，专为现代 Apple Music TTML 结构设计，提供全面的歌词格式转换、处理和优化功能。</p><p><a href="https://github.com/ranhengzhang/c-ttml-trans-tool" target="_blank" rel="noreferrer">GitHub 仓库</a> | <a href="https://deepwiki.com/ranhengzhang/c-ttml-trans-tool" target="_blank" rel="noreferrer">DeepWiki 详细文档</a></p><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><p>本项目的 GitHub README 已过时，详情请以 <a href="https://deepwiki.com/ranhengzhang/c-ttml-trans-tool" target="_blank" rel="noreferrer">DeepWiki 文档</a> 为准。</p></div><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h2><ul><li>C++23 或更高版本</li><li>Qt 5.15+ 或 Qt 6.x</li><li>CMake 3.5+（子模块 lyric 需要 3.20+）</li><li>MSVC（Visual Studio 2022 或更高版本，需启用 <code>/Zc:preprocessor</code> 和 <code>/Zc:__cplusplus</code>）</li></ul><h2 id="构建模块" tabindex="-1">构建模块 <a class="header-anchor" href="#构建模块" aria-label="Permalink to &quot;构建模块&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>类型</th><th>职责</th></tr></thead><tbody><tr><td><code>lyric</code></td><td>静态库</td><td>核心数据模型（LyricObject、LyricTime）与解析器</td></tr><tr><td><code>widgets</code></td><td>静态库</td><td>自定义 UI 组件（如 MPlainTextEdit）</td></tr><tr><td><code>dialogs</code></td><td>静态库</td><td>主窗口与辅助对话框逻辑</td></tr><tr><td><code>ttml-tool</code></td><td>可执行文件</td><td>应用程序入口与系统集成</td></tr></tbody></table><h2 id="已实现功能" tabindex="-1">已实现功能 <a class="header-anchor" href="#已实现功能" aria-label="Permalink to &quot;已实现功能&quot;">​</a></h2><h3 id="格式转换" tabindex="-1">格式转换 <a class="header-anchor" href="#格式转换" aria-label="Permalink to &quot;格式转换&quot;">​</a></h3><p>支持读取 TTML 并导出为以下格式：</p><ul><li>TTML</li><li>ASS</li><li>LRC（以 Walkman NW-A45 显示效果为准）</li><li>SPL</li><li>LYS</li><li>QRC</li><li>YRC</li><li>KRC</li><li>TXT</li></ul><h3 id="复制原文" tabindex="-1">复制原文 <a class="header-anchor" href="#复制原文" aria-label="Permalink to &quot;复制原文&quot;">​</a></h3><p>支持将原文以以下格式复制到剪贴板：</p><ul><li>TTML</li><li>ASS</li><li>LRC</li><li>SPL</li><li>LYS</li><li>QRC</li><li>YRC</li><li>KRC</li><li>TXT</li></ul><h3 id="时间处理" tabindex="-1">时间处理 <a class="header-anchor" href="#时间处理" aria-label="Permalink to &quot;时间处理&quot;">​</a></h3><ul><li>全局时间轴偏移</li><li>精度调整</li></ul><h3 id="繁简转换" tabindex="-1">繁简转换 <a class="header-anchor" href="#繁简转换" aria-label="Permalink to &quot;繁简转换&quot;">​</a></h3><p>集成 OpenCC，支持高精度简繁中文转换：</p><ul><li>简转繁</li><li>繁转简</li></ul><h3 id="元数据管理" tabindex="-1">元数据管理 <a class="header-anchor" href="#元数据管理" aria-label="Permalink to &quot;元数据管理&quot;">​</a></h3><ul><li>复制为 Markdown 格式 Pr 正文（预设元数据）</li><li>复制为 Markdown 格式表格（扩展元数据）</li></ul><h2 id="未实现功能" tabindex="-1">未实现功能 <a class="header-anchor" href="#未实现功能" aria-label="Permalink to &quot;未实现功能&quot;">​</a></h2><ul><li>解析 LYS、QRC、YRC、KRC 格式文件</li><li>KRC 编码 / 解码</li><li>Win Toast 提示</li></ul><h2 id="技术架构" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构" aria-label="Permalink to &quot;技术架构&quot;">​</a></h2><p>工具分为三个核心层次：</p><h3 id="数据模型层" tabindex="-1">数据模型层 <a class="header-anchor" href="#数据模型层" aria-label="Permalink to &quot;数据模型层&quot;">​</a></h3><p>基于 <code>LyricObject</code> → <code>LyricLine</code> → <code>LyricSyl</code> 三层结构构建的核心数据模型，配合 <code>LyricTime</code> 时间戳抽象类和 <code>Agent</code> 贡献者信息类。</p><h3 id="序列化层" tabindex="-1">序列化层 <a class="header-anchor" href="#序列化层" aria-label="Permalink to &quot;序列化层&quot;">​</a></h3><p>通过分发模式实现多格式导出，<code>LyricObject</code> 遍历 <code>LyricLine</code> 集合，再由 <code>LyricLine</code> 遍历 <code>LyricSyl</code> 音节单元生成目标格式。</p><h3 id="用户界面层" tabindex="-1">用户界面层 <a class="header-anchor" href="#用户界面层" aria-label="Permalink to &quot;用户界面层&quot;">​</a></h3><p>基于 Qt Widgets 的桌面 GUI，提供主窗口控制器、语言选择对话框、时间格式对话框等交互界面。</p><h2 id="ipc-支持" tabindex="-1">IPC 支持 <a class="header-anchor" href="#ipc-支持" aria-label="Permalink to &quot;IPC 支持&quot;">​</a></h2><ul><li>管道名称：<code>C_TTML_TOOL</code></li><li>使用 <code>QLocalServer</code> 向连接的客户端流式传输 UTF-8 TTML 内容</li></ul><h2 id="多平台支持" tabindex="-1">多平台支持 <a class="header-anchor" href="#多平台支持" aria-label="Permalink to &quot;多平台支持&quot;">​</a></h2><table tabindex="0"><thead><tr><th>平台</th><th>支持方式</th></tr></thead><tbody><tr><td>Windows</td><td>唯一平台，单实例控制（Mutex）</td></tr></tbody></table><p>别的不要想了。</p><h2 id="许可" tabindex="-1">许可 <a class="header-anchor" href="#许可" aria-label="Permalink to &quot;许可&quot;">​</a></h2><p>本项目采用 GNU 通用公共许可证第 3 版（GPL-3.0-or-later）授权。</p>',39)])])}const b=t(r,[["render",o]]);export{p as __pageData,b as default};
